-- BrandKraf — BM translation batch 1 (6 high-intent articles). Run AFTER blog-i18n-migration.sql.
-- Fills title_ms / excerpt_ms / content_ms. Content is dollar-quoted ($ms$...$ms$). Safe to re-run.
-- In-content links use /ms/ so Malay readers stay in Malay. Re-run generate-sitemap (next deploy) to list them.

update public.blog_posts set
  title_ms = 'Pemasaran TikTok untuk Perniagaan Malaysia: Panduan Lengkap',
  excerpt_ms = 'TikTok ialah platform paling berkuasa untuk jenama Malaysia hari ini. Pelajari cara berkembang dan menjual di TikTok dengan kandungan yang menarik perhatian dan menukar penonton kepada pelanggan.',
  content_ms = $ms$<p>TikTok bukan lagi sekadar aplikasi tarian dan trend — ia telah menjadi salah satu saluran pemasaran paling berkesan untuk perniagaan di Malaysia. Algoritmanya memberi ganjaran kepada kandungan yang bagus, bukan jumlah pengikut, jadi akaun baharu pun boleh mencapai jutaan orang. Panduan ini menerangkan cara memanfaatkannya.</p>
<blockquote>Di TikTok, anda tidak perlu ramai pengikut untuk menjadi viral. Anda perlukan video yang ingin ditolak oleh algoritma.</blockquote>
<h2>Mengapa TikTok berbeza</h2>
<p>Tidak seperti platform lain, TikTok menunjukkan kandungan anda kepada orang yang belum mengikuti anda melalui halaman <strong>For You</strong>. Ini bermakna setiap video ialah peluang untuk menjangkau penonton baharu — sesuatu yang sukar dicapai di platform lain. Untuk perniagaan kecil, ini ialah peluang besar.</p>
<h2>Kail 3 saat pertama</h2>
<p>TikTok menilai sama ada untuk menolak video anda berdasarkan berapa lama orang menontonnya. Jika anda hilang penonton dalam tiga saat pertama, jangkauan anda terhenti. Mulakan dengan kenyataan berani, soalan, atau visual yang mengejutkan untuk menghentikan jari daripada menyusur.</p>
<h2>Jadilah autentik, bukan sempurna</h2>
<p>Kandungan yang terlalu digilap selalunya berprestasi lemah di TikTok. Penonton mahukan video yang terasa nyata dan jujur. Video yang dirakam dengan telefon yang benar-benar membantu akan mengatasi iklan mahal — sebab itulah <a href="/ms/blog/what-is-ugc-why-your-brand-needs-it">UGC</a> begitu berkesan.</p>
<h2>Naiki trend dengan pantas</h2>
<p>Menggunakan bunyi dan format yang sedang trending memberi algoritma alasan tambahan untuk menolak kandungan anda. Tetapi kepantasan penting — trend pudar dalam beberapa hari. Letakkan sentuhan jenama anda pada trend, jangan sekadar meniru.</p>
<h2>Jual tanpa terasa seperti menjual</h2>
<p>Penonton TikTok tidak suka iklan keras. Galakkan jualan dengan menunjukkan produk anda menyelesaikan masalah sebenar, menggunakan bukti sosial, dan beralih ke jualan langsung. Lihat panduan kami tentang <a href="/ms/blog/how-to-sell-on-tiktok-shop-malaysia">cara menjual di TikTok Shop</a>.</p>
<h2>Konsisten dan banyakkan</h2>
<p>Tiada siapa boleh meramal video mana yang akan meletup. Jawapannya ialah kuantiti yang berkualiti — siar secara konsisten, pelajari apa yang berkesan, dan ulanginya. Satu video viral boleh mengubah perniagaan anda.</p>
<h2>Soalan lazim</h2>
<h3>Perlukah saya ramai pengikut untuk berjaya di TikTok?</h3>
<p>Tidak. TikTok menolak kandungan berdasarkan penglibatan, bukan jumlah pengikut, jadi akaun baharu menjadi viral setiap hari.</p>
<h3>Berapa kerap saya patut menyiar?</h3>
<p>Konsisten lebih penting daripada kuantiti, tetapi di platform penemuan seperti TikTok, lebih banyak kandungan berkualiti meningkatkan peluang anda. Cuba siar setiap hari jika mampu.</p>
<h3>Bahasa apa patut saya guna?</h3>
<p>Gunakan bahasa yang penonton sasaran anda guna — Bahasa Melayu, Inggeris, atau campuran. Keaslian lebih penting.</p>
<p>BrandKraf membantu jenama Malaysia menang di TikTok. Terokai <a href="/ms/guides/tiktok-marketing">panduan pemasaran TikTok</a> kami, <a href="/ms/portfolio/tiktok-live-service">perkhidmatan TikTok Live</a>, atau <a href="/ms/contact">hubungi kami</a>.</p>$ms$
where slug = 'tiktok-marketing-malaysian-businesses';

update public.blog_posts set
  title_ms = 'Pemasaran Media Sosial 101 untuk PKS Malaysia',
  excerpt_ms = 'Baharu dalam pemasaran media sosial? Panduan ini menerangkan asas yang perlu diketahui setiap perniagaan kecil Malaysia — memilih platform, mencipta kandungan, dan menukar pengikut kepada pelanggan.',
  content_ms = $ms$<p>Media sosial ialah tempat jenama Malaysia ditemui, dinilai, dan dipilih. Tetapi bagi perniagaan kecil yang baru bermula, ia boleh terasa membingungkan. Panduan ini memecahkan asas yang anda perlukan untuk bermula dengan yakin.</p>
<blockquote>Anda tidak perlu berada di setiap platform. Anda perlu berada di tempat pelanggan anda berada — dan lakukannya dengan baik.</blockquote>
<h2>Mula dengan strategi, bukan platform</h2>
<p>Sebelum membuka akaun, fahami siapa pelanggan anda, apa yang mereka pedulikan, dan matlamat anda. Strategi yang jelas menjadikan setiap siaran lebih berkesan daripada menyiar secara rawak.</p>
<h2>Pilih platform yang betul</h2>
<p>Anda tidak perlu menguasai semua platform. Fokus pada satu atau dua tempat penonton anda aktif — TikTok dan Instagram untuk penonton muda, Facebook untuk audiens yang lebih luas di Malaysia, LinkedIn untuk B2B. Lebih baik cemerlang di satu platform daripada lemah di lima.</p>
<h2>Cipta kandungan bernilai</h2>
<p>Kandungan terbaik mengajar, menghiburkan, atau memberi inspirasi. Gunakan campuran video pendek, karusel, dan siaran yang membina kepercayaan. Untuk idea, lihat <a href="/ms/blog/social-media-content-ideas">50 idea kandungan media sosial</a> kami.</p>
<h2>Konsisten ialah kunci</h2>
<p>Algoritma dan penonton memberi ganjaran kepada kekonsistenan. Lebih baik menyiar tiga kali seminggu selamanya daripada setiap hari selama dua minggu kemudian senyap. Pilih kadar yang anda mampu kekalkan.</p>
<h2>Libatkan diri, jangan sekadar menyiar</h2>
<p>Media sosial bersifat sosial. Balas komen, jawab DM, dan bina hubungan sebenar. Akaun yang berinteraksi berkembang lebih pantas.</p>
<h2>Tukar pengikut kepada pelanggan</h2>
<p>Pengikut bukan matlamat — pelanggan ialah matlamat. Gunakan ajakan bertindak yang jelas, balas mesej dengan pantas, dan pandu penonton ke arah pembelian. Pengikut yang terlibat jauh lebih bernilai daripada nombor besar yang pasif.</p>
<h2>Soalan lazim</h2>
<h3>Platform mana patut saya mulakan?</h3>
<p>Mula di tempat penonton anda berada. Untuk kebanyakan PKS Malaysia, itu bermaksud TikTok, Instagram, atau Facebook.</p>
<h3>Berapa kerap saya patut menyiar?</h3>
<p>Pilih kadar yang boleh dikekalkan — kekonsistenan mengatasi kuantiti. Tiga kali seminggu yang konsisten sudah memadai untuk bermula.</p>
<h3>Perlukah saya bayar untuk iklan?</h3>
<p>Anda boleh bermula secara organik, tetapi iklan berbayar mempercepat pertumbuhan apabila anda bersedia. Mulakan dengan kandungan organik yang kukuh dahulu.</p>
<p>BrandKraf menguruskan media sosial untuk jenama Malaysia. Terokai <a href="/ms/guides/social-media-marketing">panduan media sosial</a> kami, <a href="/ms/portfolio/social-media-management">perkhidmatan kami</a>, atau <a href="/ms/contact">hubungi kami</a>.</p>$ms$
where slug = 'social-media-marketing-101-smes';

update public.blog_posts set
  title_ms = 'Apa Itu UGC dan Mengapa Jenama Anda Memerlukannya',
  excerpt_ms = 'Kandungan jana pengguna (UGC) menukar lebih baik daripada iklan digilap kerana ia terasa nyata. Pelajari apa itu UGC, mengapa ia berkesan, dan cara menggunakannya untuk jenama anda.',
  content_ms = $ms$<p>Pengguna lebih mempercayai orang lain berbanding jenama. Itulah sebabnya kandungan jana pengguna (UGC) kini mengatasi pengiklanan yang digilap — ia terasa autentik, dan autentik itu menukar. Inilah yang perlu diketahui setiap jenama Malaysia.</p>
<blockquote>Orang tidak percaya iklan. Mereka percaya orang lain. UGC ialah orang lain itu, bercakap untuk jenama anda.</blockquote>
<h2>Apa itu UGC sebenarnya</h2>
<p>Pencipta UGC diupah untuk <strong>kemahiran mencipta kandungan, bukan saiz pengikut</strong>. Tidak seperti pempengaruh, mereka mungkin tidak menyiar kepada pengikut sendiri — mereka menyerahkan kepada anda video autentik yang sedia untuk iklan, yang boleh anda gunakan sebagai iklan atau siar sendiri.</p>
<h2>Mengapa UGC berkesan</h2>
<p>UGC terasa seperti cadangan daripada kawan, bukan iklan daripada syarikat. Keaslian ini mengurangkan keraguan dan meningkatkan kadar penukaran. Ia juga jauh lebih kos efektif daripada penggambaran studio.</p>
<h2>Jenis UGC</h2>
<ul><li><strong>Testimoni</strong> — pelanggan berkongsi pengalaman mereka.</li><li><strong>Buka kotak (unboxing)</strong> — kegembiraan menerima produk.</li><li><strong>Demonstrasi produk</strong> — produk dalam tindakan.</li><li><strong>Gaya hidup</strong> — produk dalam kehidupan sebenar.</li></ul>
<h2>Mengapa hak penggunaan penting</h2>
<p>Bayaran penciptaan yang rendah tidak bermakna jika anda tidak boleh menggunakan kandungan itu dalam iklan berbayar secara sah. Sentiasa persetujui hak penggunaan secara bertulis. Lihat <a href="/ms/blog/ugc-creator-rates-malaysia">kadar pencipta UGC di Malaysia</a> kami.</p>
<h2>Cara menggunakan UGC</h2>
<p>Letakkan UGC di halaman produk, dalam iklan, di media sosial, dan di e-mel. Satu video UGC yang kukuh boleh mengatasi penggambaran mahal pada kos yang lebih rendah — uji beberapa variasi dan kembangkan yang berkesan.</p>
<h2>Soalan lazim</h2>
<h3>Adakah UGC lebih murah daripada pemasaran pempengaruh?</h3>
<p>Selalunya ya — kerana anda membayar untuk kandungan, bukan penonton. Tetapi pertimbangkan hak penggunaan jika anda merancang untuk menjalankan iklan berbayar.</p>
<h3>Berapa banyak video saya perlukan untuk bermula?</h3>
<p>Mulakan dengan tiga hingga lima variasi supaya anda boleh menguji sudut yang berbeza, kemudian kembangkan yang menang.</p>
<h3>Perlukah pencipta UGC ramai pengikut?</h3>
<p>Tidak. Nilai mereka ialah kandungan. Saiz penonton ialah apa yang anda bayar kepada pempengaruh — strategi berbeza.</p>
<p>BrandKraf menghasilkan UGC sedia iklan untuk jenama Malaysia. Terokai <a href="/ms/guides/ugc-influencer-marketing">panduan UGC</a> kami, <a href="/ms/portfolio/ugc-content-creation">perkhidmatan UGC</a>, atau <a href="/ms/contact">hubungi kami</a>.</p>$ms$
where slug = 'what-is-ugc-why-your-brand-needs-it';

update public.blog_posts set
  title_ms = 'Panduan Iklan Facebook & Meta untuk Pemula',
  excerpt_ms = 'Iklan Facebook dan Instagram boleh mengembangkan perniagaan anda — jika dilakukan dengan betul. Pelajari cara Meta Ads berfungsi, penyasaran, kreatif, dan cara mengelak membazir bajet.',
  content_ms = $ms$<p>Iklan Facebook dan Instagram (Meta Ads) meletakkan jenama anda di hadapan penonton yang tepat dengan penyasaran yang luar biasa. Ia berkuasa — tetapi juga mudah membazir wang jika anda tidak memahami asasnya. Panduan ini membantu anda bermula dengan selamat.</p>
<blockquote>Meta Ads mencipta permintaan yang anda tidak tahu wujud. Itulah kekuatannya — dan jebakannya jika tersilap.</blockquote>
<h2>Mengapa Meta Ads berkesan</h2>
<p>Meta mempunyai data terperinci tentang minat dan tingkah laku berjuta-juta rakyat Malaysia. Ini membolehkan anda menjangkau orang yang berkemungkinan besar berminat dengan produk anda — walaupun mereka tidak mencarinya.</p>
<h2>Mulakan dengan matlamat yang jelas</h2>
<p>Sebelum membuat iklan, tentukan matlamat: kesedaran, trafik, petunjuk, atau jualan. Meta mengoptimumkan penghantaran berdasarkan matlamat yang anda pilih, jadi memilih yang betul adalah penting.</p>
<h2>Fahami penyasaran</h2>
<p>Anda boleh menyasarkan mengikut demografi, minat, tingkah laku, dan penonton serupa (lookalike). Untuk bermula, jangan terlalu sempit — beri algoritma ruang untuk belajar siapa yang menukar.</p>
<h2>Kreatif ialah segalanya</h2>
<p>Di media sosial, iklan yang kelihatan seperti iklan akan dilangkau. Iklan video bergaya UGC selalunya mengatasi penggambaran yang digilap. Tambah kapsyen kerana kebanyakan orang menonton tanpa bunyi.</p>
<h2>Pasang Pixel anda</h2>
<p>Meta Pixel menjejaki apa yang orang lakukan di laman web anda, membolehkan penjejakan penukaran dan iklan penyasaran semula. Pasang ia sebelum membelanjakan seringgit pun.</p>
<h2>Jangan membazir bajet</h2>
<p>Kesilapan pemula yang biasa: berhenti iklan terlalu awal, menukar terlalu kerap, atau tidak menjejaki penukaran. Beri iklan masa untuk belajar, dan nilai berdasarkan pulangan, bukan rasa hati — lihat panduan <a href="/ms/blog/how-to-improve-roas">ROAS</a> kami.</p>
<h2>Soalan lazim</h2>
<h3>Berapa bajet patut saya mulakan?</h3>
<p>Mulakan kecil, buktikan ia menguntungkan, kemudian kembangkan secara beransur. Tiada minimum tetap — disiplin lebih penting daripada saiz.</p>
<h3>Facebook atau Instagram?</h3>
<p>Kedua-duanya dalam ekosistem Meta. Biarkan platform mengoptimumkan penempatan, atau fokus pada tempat penonton anda paling aktif.</p>
<h3>Mengapa iklan saya tidak menukar?</h3>
<p>Selalunya kreatif lemah, penyasaran salah, atau halaman pendaratan yang tidak meyakinkan. Betulkan asas dahulu sebelum menambah bajet.</p>
<p>BrandKraf menjalankan kempen Meta yang menguntungkan untuk jenama Malaysia. Terokai <a href="/ms/guides/paid-advertising">panduan pengiklanan berbayar</a> kami, <a href="/ms/portfolio/paid-advertising">perkhidmatan iklan</a>, atau <a href="/ms/contact">hubungi kami</a>.</p>$ms$
where slug = 'facebook-meta-ads-beginners-guide';

update public.blog_posts set
  title_ms = 'Kos Pemasaran Digital di Malaysia (2026): Panduan Harga Telus',
  excerpt_ms = 'Berapa sebenarnya kos pemasaran digital di Malaysia pada 2026? Pecahan jelas mengikut saluran — SEO, iklan, media sosial, dan perkhidmatan penuh — serta cara merancang bajet.',
  content_ms = $ms$<p>"Berapa kos pemasaran digital?" ialah soalan pertama hampir setiap pemilik perniagaan Malaysia — dan paling sukar mendapat jawapan jelas. Sebut harga berbeza-beza daripada beberapa ratus ringgit hingga lima angka sebulan. Panduan ini memberi anda angka sebenar 2026.</p>
<blockquote>Pemasaran murah yang tidak menukar ialah pemasaran paling mahal. Harga ialah apa yang anda bayar; ROI ialah apa yang anda simpan.</blockquote>
<h2>Apa yang anda sebenarnya bayar</h2>
<p>Yuran pemasaran digital biasanya merangkumi strategi, penciptaan kandungan, pengurusan iklan, alat, dan pelaporan. Apabila membandingkan sebut harga, bandingkan skop — bukan sekadar nombor di bawah.</p>
<h2>Julat harga tipikal di Malaysia (2026)</h2>
<ul>
<li><strong>SEO</strong> — dari sekitar RM1,500/bulan untuk pengoptimuman berterusan.</li>
<li><strong>Pengurusan iklan Google atau Meta</strong> — RM800–RM1,500/bulan <em>di atas</em> perbelanjaan iklan anda.</li>
<li><strong>Pengurusan media sosial</strong> — RM2,500–RM5,000/bulan untuk kebanyakan PKS.</li>
<li><strong>Perkhidmatan penuh (pelbagai saluran)</strong> — RM3,000–RM8,000/bulan.</li>
<li><strong>Pekerja bebas (freelancer)</strong> — titik masuk lebih murah, tetapi kapasiti terhad.</li>
</ul>
<p>Kebanyakan PKS berada antara RM1,500 dan RM8,000 sebulan sebelum perbelanjaan iklan.</p>
<h2>Pekerja bebas vs agensi vs dalaman</h2>
<p>Pekerja bebas paling murah tetapi satu titik kegagalan. Agensi lebih mahal tetapi anda dapat satu pasukan dan akauntabiliti. Pekerja dalaman selalunya melebihi yuran agensi sebaik dikira gaji dan KWSP/PERKESO.</p>
<h2>Jangan lupa Geran Digitalisasi PKS</h2>
<p>PKS Malaysia yang layak boleh menuntut <strong>50% kos digitalisasi, sehingga RM5,000</strong>. Lihat panduan <a href="/ms/blog/sme-digitalisation-grant-2026">Geran Digitalisasi PKS</a> kami.</p>
<h2>Cara merancang bajet dengan bijak</h2>
<p>Mulakan dengan matlamat, bukan nombor. Tentukan nilai seorang pelanggan baharu, kemudian kira ke belakang. Titik permulaan biasa ialah 7–10% daripada hasil. Jejaki <a href="/ms/blog/how-to-improve-roas">pulangan</a> dari hari pertama.</p>
<h2>Soalan lazim</h2>
<h3>Berapa patut perniagaan kecil belanja untuk pemasaran digital?</h3>
<p>Kebanyakan PKS bermula antara RM1,500 dan RM3,000 sebulan dan berkembang apabila keputusan terbukti.</p>
<h3>Adakah perbelanjaan iklan termasuk dalam yuran agensi?</h3>
<p>Biasanya tidak. Yuran pengurusan dan bajet yang anda bayar kepada Google atau Meta ialah item berasingan.</p>
<h3>Mengapa SEO ialah kos berterusan?</h3>
<p>Kedudukan memerlukan kandungan, penyelenggaraan teknikal, dan pembinaan pautan berterusan kerana pesaing juga berusaha. SEO ialah pelaburan yang berkompaun.</p>
<h3>Bolehkah saya buat sendiri untuk menjimatkan wang?</h3>
<p>Anda boleh mula, terutamanya media sosial organik. Tetapi apabila berkembang, kos peluang masa anda menjadikan bantuan profesional berbaloi.</p>
<p>BrandKraf memberi harga telus dan berfokuskan hasil. Lihat <a href="/ms/pricing">harga</a> kami atau <a href="/ms/contact">dapatkan sebut harga</a>.</p>$ms$
where slug = 'digital-marketing-cost-malaysia';

update public.blog_posts set
  title_ms = 'Geran Digitalisasi PKS 2026: Cara Tuntut Sehingga RM5,000 untuk Pemasaran',
  excerpt_ms = 'Geran Digital PMKS MADANI menanggung 50% kos digitalisasi anda, sehingga RM5,000. Berikut ialah siapa yang layak, apa yang dilindungi, dan cara memohon langkah demi langkah.',
  content_ms = $ms$<p>Jika anda menjalankan PKS di Malaysia, kerajaan mungkin membayar separuh daripada penyediaan pemasaran digital anda. Geran Digitalisasi PKS — kini di bawah <strong>Geran Digital PMKS MADANI</strong> — menanggung <strong>50% kos digitalisasi yang layak, sehingga RM5,000</strong> setiap syarikat. Ramai pemilik perniagaan tidak sedar mereka layak.</p>
<blockquote>Geran yang menanggung separuh penyediaan digital anda bukan sekadar penjimatan — ia permulaan yang mungkin diabaikan pesaing anda.</blockquote>
<h2>Apa yang dilindungi geran</h2>
<p>Geran ini direka untuk membantu PKS mengguna pakai alat digital. Kategori yang layak biasanya termasuk:</p>
<ul>
<li>Penyediaan pemasaran digital dan kehadiran dalam talian.</li>
<li>Platform e-dagang dan jualan dalam talian.</li>
<li>Laman web dan kedai digital.</li>
<li>Perkhidmatan digitalisasi lain yang diluluskan.</li>
</ul>
<p>Oleh sebab senarai dikemas kini dari semasa ke semasa, sahkan sebelum memohon.</p>
<h2>Siapa yang layak</h2>
<ul>
<li>PKS milik rakyat Malaysia (biasanya 60% atau lebih ekuiti tempatan).</li>
<li>Berdaftar dengan SSM dan beroperasi untuk tempoh minimum.</li>
<li>Dalam ambang hasil dan pekerja yang ditetapkan untuk PKS.</li>
</ul>
<h2>Cara memohon, langkah demi langkah</h2>
<ol>
<li><strong>Sahkan kelayakan</strong> berdasarkan kriteria semasa.</li>
<li><strong>Pilih pembekal penyelesaian yang diluluskan</strong>.</li>
<li><strong>Dapatkan sebut harga</strong> untuk perkhidmatan yang layak.</li>
<li><strong>Hantar permohonan</strong> dengan dokumen SSM, IC, butiran bank, dan sebut harga.</li>
<li><strong>Tunggu kelulusan</strong>, kemudian teruskan dengan pembekal.</li>
</ol>
<p>Subsidi 50% dikenakan pada jumlah yang layak, dihadkan pada RM5,000.</p>
<h2>Cara memanfaatkan geran sepenuhnya</h2>
<p>Gunakan geran untuk aset yang terus memberi pulangan: laman web yang menukar, penyediaan e-dagang, atau pakej pemasaran asas. Rancang bajet berterusan yang realistik — lihat panduan <a href="/ms/blog/digital-marketing-cost-malaysia">kos pemasaran digital</a> kami.</p>
<h2>Soalan lazim</h2>
<h3>Adakah geran masih tersedia pada 2026?</h3>
<p>Sokongan digitalisasi PKS telah berjalan dalam beberapa kitaran. Sahkan status program semasa dan baki peruntukan sebelum memohon.</p>
<h3>Berapa banyak boleh saya dapat?</h3>
<p>Sehingga RM5,000, dikira sebagai 50% daripada kos digitalisasi yang layak, sekali setiap syarikat.</p>
<h3>Bolehkah ia menanggung pemasaran digital secara khusus?</h3>
<p>Pemasaran digital dan kehadiran dalam talian biasanya dalam skop, bergantung pada program semasa dan pembekal anda.</p>
<h3>Perlukah pembekal yang diluluskan?</h3>
<p>Ya. Perkhidmatan biasanya perlu disampaikan oleh pembekal penyelesaian berdaftar untuk tuntutan yang sah.</p>
<p>BrandKraf boleh membantu PKS yang layak merancang projek mesra geran. <a href="/ms/contact">Hubungi kami</a> atau terokai <a href="/ms/pricing">pakej kami</a>.</p>$ms$
where slug = 'sme-digitalisation-grant-2026';
